int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin &gt;&gt; T;
    while(T--){
        int N;
        cin &gt;&gt; N;
        vector&lt;int&gt; A(N);
        for (int i = 0; i &lt; N; i++){
            cin &gt;&gt; A[i];
        }
        long long ans = 0;
        const int MAX_BITS = 31;
        vector&lt;int&gt; bitCount(MAX_BITS, 0);
        for (int i = 0; i &lt; N; i++){
            for (int bit = 0; bit &lt; MAX_BITS; bit++){
                if (A[i] &amp; (1 &lt;&lt; bit)) {
                    ans += i - bitCount[bit];
                    bitCount[bit]++;
                } else {
                    ans += bitCount[bit];
                }
            }
        }
        cout &lt;&lt; ans &lt;&lt; "\n";
    }
    return 0;
}
